// =====================================================
// Featured parts — composable units used by Kingdom of
// Eldgate and its connected regions.
// =====================================================

// Stone fountain — water at the center, rocks at corners.
part Fountain {
  size 3, 3;
  fill STONE from (0,0) to (2,2);
  tile ROCK  at (0,0);
  tile ROCK  at (2,0);
  tile ROCK  at (0,2);
  tile ROCK  at (2,2);
  tile WATER at (1,1);
  tile FLOWER at (1,1);
}

// Market stall — wooden frame with a banner above an open front.
part MarketStall {
  size 3, 2;
  tile WALL_WOOD at (0,0);
  tile BANNER    at (1,0);
  tile WALL_WOOD at (2,0);
  tile WALL_WOOD at (0,1);
  tile DOOR_WOOD at (1,1);   // open front
  tile WALL_WOOD at (2,1);
}

// Coastal lighthouse — stone tower, torch on top, door at base.
part Lighthouse {
  size 3, 4;
  tile BRICK       at (0,0);
  tile TORCH       at (1,0);
  tile BRICK       at (2,0);
  tile WALL_STONE  at (0,1);
  tile WINDOW_STONE at (1,1);
  tile WALL_STONE  at (2,1);
  tile WALL_STONE  at (0,2);
  tile WALL_STONE  at (1,2);
  tile WALL_STONE  at (2,2);
  tile WALL_STONE  at (0,3);
  tile DOOR_STONE  at (1,3);
  tile WALL_STONE  at (2,3);
}

// Chicken coop — fenced dirt area with chickens and a south gate.
part ChickenCoop {
  size 5, 4;
  fill DIRT from (0,0) to (4,3);
  row FENCE from (0,0) to (4,0);     // north
  tile FENCE at (0,3);
  tile FENCE at (1,3);
  // gap at (2,3) = gate
  tile FENCE at (3,3);
  tile FENCE at (4,3);
  tile FENCE at (0,1);
  tile FENCE at (0,2);
  tile FENCE at (4,1);
  tile FENCE at (4,2);
  tile CHICKEN at (1,1);
  tile CHICKEN at (3,1);
  tile CHICKEN at (2,2);
  tile WATER   at (1,2);  // a small drinking trough
}

// Crop field — three rows of mature crops.
part CropField {
  size 5, 3;
  fill DIRT from (0,0) to (4,2);
  row CROP_STRAWBERRY from (0,0) to (4,0);
  row CROP_LEEK       from (0,1) to (4,1);
  row CROP_POTATO     from (0,2) to (4,2);
}

// Cow pasture — fenced grass with cows; gate on south middle.
part Pasture {
  size 6, 5;
  row FENCE from (0,0) to (5,0);
  tile FENCE at (0,4);
  tile FENCE at (1,4);
  // gap at (2,4) and (3,4)
  tile FENCE at (4,4);
  tile FENCE at (5,4);
  tile FENCE at (0,1);
  tile FENCE at (0,2);
  tile FENCE at (0,3);
  tile FENCE at (5,1);
  tile FENCE at (5,2);
  tile FENCE at (5,3);
  tile COW at (2,2);
  tile COW at (4,3);
}

// A preview standalone scene to inspect the parts.
map Preview {
  size 24, 14;
  place Fountain    at (1,1);
  place MarketStall at (1,7);
  place Lighthouse  at (6,1);
  place ChickenCoop at (10,1);
  place CropField   at (16,1);
  place Pasture     at (16,8);
  player at (12,10);
}
